          if (worst_arrival > node_data.required[phase] + epsilon)
            continue;
        }

        bool accept = false;
        if (compare_map<DO_AREA>(worst_arrival, best_arrival, area_local, best_area_flow, cut->size(), best_size)) {
            accept = true;
        } else {
            // Combined delta considering both arrival and area
            double delta = (worst_arrival - best_arrival) + 0.5 * (area_local - best_area_flow);
            double probability = exp(-delta / temperature);
            if (rand() / static_cast<double>(RAND_MAX) < probability) {
