            best_arrival = worst_arrival;
            best_area_flow = area_local;
            best_size = cut->size();
            best_cut = cut_index;
            best_area = gate.area;
            best_phase = gate_polarity;
            best_supergate = &gate;
        }
      }

      ++cut_index;
    }

